from collections import deque, defaultdict

def findLadders(beginWord: str, endWord: str, wordList: list[str]) -> list[list[str]]:
    word_set = set(wordList)
    if endWord not in word_set: return []
    graph: dict[str, list[str]] = defaultdict(list)
    distance: dict[str, int] = {beginWord: 0}
    queue = deque([beginWord])
    while queue:
        word = queue.popleft()
        if word == endWord: break
        for i in range(len(word)):
            for c in 'abcdefghijklmnopqrstuvwxyz':
                nw = word[:i] + c + word[i+1:]
                if nw in word_set:
                    if nw not in distance:
                        distance[nw] = distance[word] + 1
                        queue.append(nw)
                    if distance[nw] == distance[word] + 1:
                        graph[word].append(nw)
    result: list[list[str]] = []
    def dfs(path):
        if path[-1] == endWord:
            result.append(path[:])
            return
        for nxt in graph.get(path[-1], []):
            if distance.get(nxt, -1) == distance[path[-1]] + 1:
                path.append(nxt)
                dfs(path)
                path.pop()
    dfs([beginWord])
    return result

